function getMax(a, b) {
  if (a >= b) {
    return a;
  }
  return b;
}

function formatScore(name, score) {
  return `${name}さんの得点: ${score}点`;
}

const greetUser = (name) => {
  return `こんにちは、${name}さん`;
};

function calc(a, operator, b) {
  if (operator === "+") {
    return a + b;
  }
  if (operator === "-") {
    return a - b;
  }
  return 0;
}
